import{_ as e,o as a,c as n,a3 as s}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Tenant Application Settings","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant Application Settings | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/tenant-settings-overview"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant Application Settings | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/tenant-settings-overview"}]]},"headers":[],"relativePath":"user-guide/tenant-settings-overview.md","filePath":"user-guide/tenant-settings-overview.md","lastUpdated":1784902400000}'),o={name:"user-guide/tenant-settings-overview.md"};function i(r,t,d,l,p,c){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="tenant-application-settings" tabindex="-1">Tenant Application Settings <a class="header-anchor" href="#tenant-application-settings" aria-label="Permalink to &quot;Tenant Application Settings&quot;">​</a></h1><p>Workspace-scoped branding and configuration with automatic fallback to Central Application defaults.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tenant Setting (if configured)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Central Application Default</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>System Default (fallback)</span></span></code></pre></div><h2 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to &quot;Guides&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Audience</th><th>Document</th></tr></thead><tbody><tr><td>Workspace admins</td><td><a href="/user-guide/tenant-settings">tenant-settings-user.md</a></td></tr><tr><td>Engineers</td><td><a href="/developer-guide/tenant-settings">tenant-settings-developer.md</a></td></tr><tr><td>Production / ops</td><td><a href="/deployment/tenant-settings">tenant-settings-production.md</a></td></tr><tr><td>Object storage (Wasabi / S3)</td><td><a href="/developer-guide/object-storage">object-storage.md</a></td></tr></tbody></table><p>Also see Central <a href="/user-guide/central-settings-overview">settings.md</a> for platform-wide defaults.</p><h2 id="what-tenants-can-configure" tabindex="-1">What tenants can configure <a class="header-anchor" href="#what-tenants-can-configure" aria-label="Permalink to &quot;What tenants can configure&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Group</th><th>Fields</th></tr></thead><tbody><tr><td><strong>General</strong></td><td>Workspace Name, Application Name (optional override), Company Name, Timezone, Locale, Currency</td></tr><tr><td><strong>Security</strong></td><td>Session timeout (minutes); <code>0</code> / Never timeout keeps users signed in until they sign out</td></tr><tr><td><strong>Branding</strong></td><td>Logo, Favicon, Button Color, Support Email</td></tr><tr><td><strong>Mail</strong></td><td>SMTP host/port/user/password/encryption, From name/address</td></tr></tbody></table><p>Tenants <strong>cannot</strong> change platform registration, maintenance mode, password policy, billing flags, or Central branding.</p><h2 id="resolution-examples" tabindex="-1">Resolution examples <a class="header-anchor" href="#resolution-examples" aria-label="Permalink to &quot;Resolution examples&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Value</th><th>Resolution</th></tr></thead><tbody><tr><td>Application title</td><td>Tenant <code>app_name</code> → Workspace Name → Central <code>app_name</code></td></tr><tr><td>Logo</td><td>Tenant logo → Central logo → system default</td></tr><tr><td>Button color</td><td>Tenant → Central → <code>#111827</code></td></tr><tr><td>Support email</td><td>Tenant → Central</td></tr><tr><td>SMTP</td><td>Tenant host configured? → Tenant SMTP : Central SMTP</td></tr></tbody></table><p>The SPA applies workspace branding after public settings load (and again after you sign in so the session can resolve your workspace). Until then the browser tab may show <strong>SaleOS</strong>; sidebar and login brand text stay blank rather than showing a placeholder product name.</p><h2 id="asset-storage" tabindex="-1">Asset storage <a class="header-anchor" href="#asset-storage" aria-label="Permalink to &quot;Asset storage&quot;">​</a></h2><p>Uploads use Laravel Storage (<code>FileUploadService</code>). Locally they live under <code>storage/app/public/</code>; in production they live on the S3-compatible bucket. Relative keys are identical in both environments:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branding/logos/…          # Central</span></span>
<span class="line"><span>branding/favicons/…       # Central</span></span>
<span class="line"><span>tenants/{workspace_uuid}/</span></span>
<span class="line"><span>  branding/logos/…</span></span>
<span class="line"><span>  branding/favicons/…</span></span></code></pre></div><p>See <a href="/developer-guide/object-storage">architecture/object-storage.md</a>.</p>`,16)])])}const h=e(o,[["render",i]]);export{u as __pageData,h as default};
